>           "bucket": "my-gcs-bucket",
>           "filename": { "$toString": "$saleDate" }
>           "format": {
>             "name": "json"
>           }
>         }
>       }
>     }
>   ],
>   { "background" : true }
> })
> ```
>
> $out writes to JSON (Javascript Object Notation) files in the root of the bucket in the
> background. Each JSON (Javascript Object Notation) file contains all of the documents
> with the same `saleDate` value. $out names each file using
> the documents' `saleDate` value converted to a string.

**Atlas:**

Atlas Cluster

> **Example:**&#x20;
>
> ```json
> db.runCommand({
>   "aggregate": "my-collection",
>   "pipeline": [
>     {
>       "$out": {
>         "atlas": {
>           "clusterName": "myTestCluster",
>           "db": "sampleDB",
>           "coll": "mySampleData"
>         }
>       }
>     }
>   ],
>   { background: true }
> })
> ```
>
> $out writes to `sampleDB.mySampleData` collection in the
> Atlas cluster named `myTestCluster` in the background.

Atlas Data Federation interprets empty strings (`""`) as `null` values when
parsing filenames. If you want Atlas Data Federation to generate parseable
filenames, wrap the field references that could have `null`
values using $convert with an empty string `onNull` value.

> **Example:** This example shows how to handle null values in the `year`
> field when creating a filename from the field value.
>
> ```json
> {
>   "$out": {
>     "s3": {
>       "bucket": "my-s3-bucket",
>       "region": "us-east-1",
>       "filename": {
>         "$concat": [
>           "big-box-store/",
>           {
>             "$convert": {
>               "input": "$year",
>               "to": "string",
>               "onNull": ""
>             }
>           }, "/"
>         ]
>       },
>       "format": {
>         "name": "json.gz",
>         "maxFileSize": "200MiB"
>       }
>     }
>   }
> }
> ```

